const webhookData = $('Webhook — Alertas').first().json;
const remoteJid = (webhookData.body?.remote_jid || webhookData.remote_jid || '').trim();
const redisValue = $input.first().json.value;
let session = {};
try { session = JSON.parse(redisValue || '{}'); } catch(e) {}
return [{ json: { remote_jid: remoteJid, session } }];

const rows = $input.all();
const sessionData = $('Code — Parse Sesión').first().json;
const remoteJid = sessionData.remote_jid;
const previousStatus = rows[0]?.json?.previous_status || 'nuevo';
const whatsappName = rows[0]?.json?.whatsapp_name || 'Sin nombre';

// Construir conversación como texto (cronológico)
const conversationLines = [...rows]
  .reverse()
  .map(row => [
    `Usuario: ${row.json.user_message || '(sin texto)'}`,
    `Bot: ${row.json.bot_response || '(sin respuesta)'}`
  ].join('\n'))
  .join('\n\n');

const promptText = `Sos un asistente de admisión escolar argentino.
Analizá la siguiente conversación de WhatsApp y devolvé ÚNICAMENTE un objeto JSON válido con exactamente esta estructura:

{
  "status": "<uno de exactamente estos valores: interesado | indeciso | no_interesado | pendiente_contacto>",
  "interes_detectado": "<descripción breve del interés o desinterés detectado, máximo 100 caracteres>",
  "resumen": "<resumen de la conversación en 2 oraciones máximo>",
  "sugerencia": "<acción concreta recomendada para el equipo de admisión>"
}

Definiciones de status:
- interesado: el usuario mostró interés claro en inscribir a un alumno
- indeciso: respuestas ambiguas, sin señal clara de interés o desinterés
- no_interesado: descartó explícitamente o dejó de responder tras una negativa
- pendiente_contacto: requiere intervención humana (caso complejo, reclamo, consulta urgente)

Conversación a analizar:
${conversationLines}

Respondé SOLO con el JSON, sin texto adicional, sin backticks, sin markdown.`;

return [{
  json: {
    remote_jid:      remoteJid,
    previous_status: previousStatus,
    whatsapp_name:   whatsappName,
    msg_count:       rows.length,
    gemini_payload: {
      contents: [{ parts: [{ text: promptText }] }],
      generationConfig: {
        temperature: 0.1,
        maxOutputTokens: 512,
        responseMimeType: 'application/json'
      },
      safetySettings: [
        { category: 'HARM_CATEGORY_HARASSMENT',        threshold: 'BLOCK_NONE' },
        { category: 'HARM_CATEGORY_HATE_SPEECH',       threshold: 'BLOCK_NONE' },
        { category: 'HARM_CATEGORY_SEXUALLY_EXPLICIT', threshold: 'BLOCK_NONE' },
        { category: 'HARM_CATEGORY_DANGEROUS_CONTENT', threshold: 'BLOCK_NONE' }
      ]
    }
  }
}];

const geminiResponse = $input.first().json;
const buildPromptData = $('Code — Build Prompt IA').first().json;

const VALID_STATUSES = ['interesado', 'indeciso', 'no_interesado', 'pendiente_contacto'];

// Detectar si hubo error en la llamada HTTP
if (geminiResponse.error || !geminiResponse.candidates) {
  return [{
    json: {
      remote_jid:        buildPromptData.remote_jid,
      whatsapp_name:     buildPromptData.whatsapp_name,
      status:            buildPromptData.previous_status, // mantener el anterior
      previous_status:   buildPromptData.previous_status,
      interes_detectado: 'Error al contactar API de IA',
      resumen:           'No se pudo analizar. Revisar manualmente.',
      sugerencia:        'Revisar la conversación en la base de datos.',
      status_changed:    false,
      email_body:        '',
      fecha_actualizacion: new Date().toLocaleString('es-AR', { timeZone: 'America/Argentina/Buenos_Aires' }),
      _api_error: true
    }
  }];
}

let aiResult = {};
try {
  const rawText = geminiResponse.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
  // Limpiar posibles backticks o prefijos de markdown
  const cleaned = rawText.replace(/^```json\s*/i, '').replace(/```\s*$/,'').trim();
  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  aiResult = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
} catch(e) {
  aiResult = {
    status: 'indeciso',
    interes_detectado: 'No se pudo parsear la respuesta de IA',
    resumen: 'Error de parseo. Revisar manualmente.',
    sugerencia: 'Revisar conversación en BD y reintentar análisis.'
  };
}

// Validar y normalizar el status
const newStatus = VALID_STATUSES.includes(aiResult.status)
  ? aiResult.status
  : 'indeciso';

const statusChanged = buildPromptData.previous_status !== newStatus;

const fecha = new Date().toLocaleString('es-AR', { timeZone: 'America/Argentina/Buenos_Aires' });

// Construir email solo si cambió el status
const emailBody = statusChanged ? `
<h2 style="font-family:sans-serif">Actualización de estado — Bot Admisión</h2>
<table border="1" cellpadding="10" cellspacing="0" style="border-collapse:collapse;font-family:sans-serif;font-size:14px">
  <tr style="background:#f0f0f0"><th>Campo</th><th>Valor</th></tr>
  <tr><td><b>Nombre WA</b></td><td>${buildPromptData.whatsapp_name}</td></tr>
  <tr><td><b>Teléfono</b></td><td>${buildPromptData.remote_jid}</td></tr>
  <tr><td><b>Estado anterior</b></td><td>${buildPromptData.previous_status}</td></tr>
  <tr><td><b>Estado nuevo</b></td><td><strong style="color:#0066cc">${newStatus}</strong></td></tr>
  <tr><td><b>Interés detectado</b></td><td>${aiResult.interes_detectado || '-'}</td></tr>
  <tr><td><b>Resumen</b></td><td>${aiResult.resumen || '-'}</td></tr>
  <tr><td><b>Sugerencia</b></td><td>${aiResult.sugerencia || '-'}</td></tr>
  <tr><td><b>Mensajes analizados</b></td><td>${buildPromptData.msg_count}</td></tr>
  <tr><td><b>Fecha</b></td><td>${fecha}</td></tr>
  <tr><td><b>Chat WA</b></td><td><a href="https://wa.me/${buildPromptData.remote_jid}">Abrir conversación</a></td></tr>
</table>
` : '';

return [{
  json: {
    remote_jid:        buildPromptData.remote_jid,
    whatsapp_name:     buildPromptData.whatsapp_name,
    status:            newStatus,
    previous_status:   buildPromptData.previous_status,
    interes_detectado: aiResult.interes_detectado || '',
    resumen:           aiResult.resumen           || '',
    sugerencia:        aiResult.sugerencia         || '',
    status_changed:    statusChanged,
    email_body:        emailBody,
    fecha_actualizacion: fecha,
    _api_error: false
  }
}];

const googleDocs = $input.all().map((item) => item.json);
const whatsappMessages = $("when message received")
  .all()
  .map((item) => item.json);

const date = new Date();
const formattedDate = `${date.getMonth() + 1} ${date.getDate()}, ${date.getFullYear()}`;

const docText = googleDocs[0].content.split("\n").join(" ");

const body = whatsappMessages[0].messages[0].text.body;

const finalPrompt = `Today's date is: ${formattedDate}\n\n${docText}\n\nUser's question:\n${body}`;

return { finalPrompt };
